//# Register Pipeline

// Pipelines data words through a number of register stages, with both
// parallel and serial inputs and outputs. Besides the obvious uses for
// serial/parallel conversion and pipeline alignment, a register pipeline can
// be part of shift-and-add algorithms such as multiplication through
// conditional addition.

// Each cycle `clock_enable` is high, the pipeline shifts by one from LSB to
// MSB, or loads a new set of parallel values. **Load overrides shift**.
// `pipe_in` feeds the LSB, and `pipe_out` read from the MSB.

// **NOTE**: `PIPE_DEPTH` must be 1 or greater.  (*Supporting a depth of zero
// would make this code far too messy and leave the parallel input/output
// ports unconnected, which will raise CAD warnings. See the [Simple Register
// Pipeline](./Register_Pipeline_Simple.html) instead.*)

// Depending on how you parameterize and use it, a register pipeline can act
// as a delay pipeline or a shift register:

// * For a delay pipeline, set `WORD_WIDTH` to the width of the data word, then
// `PIPE_DEPTH` to the number of delay stages. This will move whole data words
// along the pipeline. 
// * For a shift register, set `WORD_WIDTH` to 1, and `PIPE_DEPTH` to the
// width of the data word you wish to shift in or out bit-by-bit. Load the
// word via `parallel_in`, then shift it out through `pipe_out`. Or, shift in
// `PIPE_DEPTH` bits through `pipe_in`, then read the data word on
// `parallel_out`.

// If no parallel loads are required, hardwire `parallel_load` to zero, and
// the multiplexers will optimize away, if any, and you'll end up with a pure
// shift register (but see the [Simple Register
// Pipeline](./Register_Pipeline_Simple.html) if this is your main use-case).
// Conversely, hardwire `parallel_load` to one, and tie off the `pipe_in`
// input, and you'll end up with a conveniently packaged bank of registers.

// The `RESET_VALUES` parameter allows each pipeline stage to start loaded
// with a known initial value, which can simplify system startup. The pipeline
// will also clear to the same values. Set `RESET_VALUES` to the concatenation
// of all initial/reset values, with the rightmost value being the first one
// (at the least-significant bit (LSB)).


`default_nettype none

module Register_Pipeline
#(
    parameter                   WORD_WIDTH      = 0,
    parameter                   PIPE_DEPTH      = 0,
    // Don't set at instantiation
    parameter                   TOTAL_WIDTH     = WORD_WIDTH * PIPE_DEPTH,

    // concatenation of each stage initial/reset value
    parameter [TOTAL_WIDTH-1:0] RESET_VALUES    = 0
)
(
    input   wire                        clock,
    input   wire                        clock_enable,
    input   wire                        clear,
    input   wire                        parallel_load,
    input   wire    [TOTAL_WIDTH-1:0]   parallel_in,
    output  reg     [TOTAL_WIDTH-1:0]   parallel_out,
    input   wire    [WORD_WIDTH-1:0]    pipe_in,
    output  reg     [WORD_WIDTH-1:0]    pipe_out
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        pipe_out = WORD_ZERO;
    end

// Each pipeline state is composed of a Multiplexer feeding a Register, so we
// can select either the output of the previous Register, or the parallel load
// data. So we need a set of input and ouput wires for each stage. 

    wire [WORD_WIDTH-1:0] pipe_stage_in     [PIPE_DEPTH-1:0];
    wire [WORD_WIDTH-1:0] pipe_stage_out    [PIPE_DEPTH-1:0];

// The following attributes prevent the implementation of the multiplexer with
// DSP blocks. This can be a useful implementation choice sometimes, but here
// it's terrible, since FPGA flip-flops usually have separate data and
// synchronous load inputs, giving us a 2:1 mux for free. If not, then we
// should use LUTs instead, or other multiplexers built into the logic blocks.

    (* multstyle = "logic" *) // Quartus
    (* use_dsp   = "no" *)    // Vivado

// We strip out first iteration of module instantiations to avoid having to
// refer to index -1 in the generate loop, and also to connect to `pipe_in`
// rather than the output of a previous register.

    Multiplexer_Binary_Behavioural
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .ADDR_WIDTH     (1),
        .INPUT_COUNT    (2)
    )
    pipe_input_select
    (
        .selector       (parallel_load),    
        .words_in       ({parallel_in[0 +: WORD_WIDTH], pipe_in}),
        .word_out       (pipe_stage_in[0])
    );

    Register
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .RESET_VALUE    (RESET_VALUES[0 +: WORD_WIDTH])
    )
    pipe_stage
    (
        .clock          (clock),
        .clock_enable   (clock_enable),
        .clear          (clear),
        .data_in        (pipe_stage_in[0]),
        .data_out       (pipe_stage_out[0])
    );

    always @(*) begin
        parallel_out[0 +: WORD_WIDTH] = pipe_stage_out[0];
    end

// Now repeat over the remainder of the pipeline stages, starting at stage 1,
// connecting each pipeline stage to the output of the previous pipeline
// stage.

    generate

        genvar i;

        for(i=1; i < PIPE_DEPTH; i=i+1) begin : pipe_stages

            (* multstyle = "logic" *) // Quartus
            (* use_dsp   = "no" *)    // Vivado

            Multiplexer_Binary_Behavioural
            #(
                .WORD_WIDTH     (WORD_WIDTH),
                .ADDR_WIDTH     (1),
                .INPUT_COUNT    (2)
            )
            pipe_input_select
            (
                .selector       (parallel_load),    
                .words_in       ({parallel_in[WORD_WIDTH*i +: WORD_WIDTH], pipe_stage_out[i-1]}),
                .word_out       (pipe_stage_in[i])
            );


            Register
            #(
                .WORD_WIDTH     (WORD_WIDTH),
                .RESET_VALUE    (RESET_VALUES[WORD_WIDTH*i +: WORD_WIDTH])
            )
            pipe_stage
            (
                .clock          (clock),
                .clock_enable   (clock_enable),
                .clear          (clear),
                .data_in        (pipe_stage_in[i]),
                .data_out       (pipe_stage_out[i])
            );

            always @(*) begin
                parallel_out[WORD_WIDTH*i +: WORD_WIDTH] = pipe_stage_out[i];
            end

        end

    endgenerate

// And finally, connect the output of the last register to the module pipe output.

    always @(*) begin
        pipe_out = pipe_stage_out[PIPE_DEPTH-1];
    end

endmodule

//# Register Pipeline (Simple)

// Pipelines data words through a number of register stages. Common uses
// include pipeline alignment, and pipelining inputs so the registers can
// retime forward into logic to allow a faster clock.

// This module is a simplification of the [Register
// Pipeline](./Register_Pipeline.html), which allows parallel input/output and
// initial values other than zero, but does not support a `PIPE_DEPTH` of
// zero like this one.

// Each cycle `clock_enable` is high, the pipeline shifts by one from
// `pipe_in` towards `pipe_out`. `clear` sets all registers to zero. If
// `PIPE_DEPTH` is zero, `pipe_in` becomes directly wired to `pipe_out` and no
// logic is inferred.

`default_nettype none

module Register_Pipeline_Simple
#(
    parameter WORD_WIDTH =  0,
    parameter PIPE_DEPTH = -1
)
(
    // If PIPE_DEPTH is zero, these are unused
    // verilator lint_off UNUSED
    input   wire                        clock,
    input   wire                        clock_enable,
    input   wire                        clear,
    // verilator lint_on  UNUSED
    input   wire    [WORD_WIDTH-1:0]    pipe_in,
    output  reg     [WORD_WIDTH-1:0]    pipe_out
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        pipe_out = WORD_ZERO;
    end

    genvar i;
    generate
        if (PIPE_DEPTH == 0) begin
            always @(*) begin
                pipe_out = pipe_in;
            end
        end
        else if (PIPE_DEPTH > 0) begin

// We strip out first iteration of Register instantiations to avoid having to
// refer to index -1 in the generate loop, and also to connect to `pipe_in`
// rather than the output of a previous register.

            wire [WORD_WIDTH-1:0] pipe [PIPE_DEPTH-1:0];

            Register
            #(
                .WORD_WIDTH     (WORD_WIDTH),
                .RESET_VALUE    (WORD_ZERO)
            )
            input_stage
            (
                .clock          (clock),
                .clock_enable   (clock_enable),
                .clear          (clear),
                .data_in        (pipe_in),
                .data_out       (pipe[0])
            );

// Now repeat over the remainder of the pipeline stages, starting at stage 1,
// connecting each pipeline stage to the output of the previous pipeline
// stage.

            for (i=1; i < PIPE_DEPTH; i=i+1) begin: pipe_stages
                Register
                #(
                    .WORD_WIDTH     (WORD_WIDTH),
                    .RESET_VALUE    (WORD_ZERO)
                )
                pipe_stage
                (
                    .clock          (clock),
                    .clock_enable   (clock_enable),
                    .clear          (clear),
                    .data_in        (pipe[i-1]),
                    .data_out       (pipe[i])
                );
            end

// And finally, connect the output of the last register to the module pipe output.

            always @(*) begin
                pipe_out = pipe[PIPE_DEPTH-1];
            end
        end
    endgenerate

endmodule

//# Variable Register Pipeline

// Delays a pipeline with variable shift-registers to adjust the latency 
// from input to output. The latency, in clock cycles, from input to output is
// selected by the `tap_number` control input, and has a maximum of
// `PIPE_DEPTH` cycles.  

// Each cycle `shift_data` is high, the pipeline shifts one word from
// `input_data` towards `output_data`. Pulse `tap_number_load` to set a new
// `tap_number`. `clear` sets all registers and the `tap_number` to zero. 

// **NOTE**: `PIPE_DEPTH` must be 16 or 32 to match the underlying AMD/Xilinx
// FPGA shift-register LUTs (SRLs). This should be trivial to port to other
// FPGA families.

// The `tap_number` is zero-indexed, so a `tap_number` of 0 selects the output
// of the first pipeline stage, and `PIPE_DEPTH-1` selects the output of the
// last pipeline stage. *It is not possible to select the input directly.*

// Changing the `tap_number` immediately changes the selected tap, and begins
// to output whatever data is at that point in the pipeline. Thus, you may
// skip data or (re)read old data.

`default_nettype none

module Register_Pipeline_Variable
#(
    parameter WORD_WIDTH = 0,
    parameter PIPE_DEPTH = 0,   // 16 or 32 only

    // Do not set at instantiation, except in Vivado IPI
    parameter ADDR_WIDTH = clog2(PIPE_DEPTH)
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire                        tap_number_load,
    input   wire    [ADDR_WIDTH-1:0]    tap_number,

    input   wire                        shift_data,
    input   wire    [WORD_WIDTH-1:0]    input_data,
    output  wire    [WORD_WIDTH-1:0]    output_data
);

    `include "clog2_function.vh"

    localparam ADDR_ZERO    = {ADDR_WIDTH{1'b0}};

// First, store the tap selection address.

    wire [ADDR_WIDTH-1:0] tap_number_current;

    Register
    #(
        .WORD_WIDTH     (ADDR_WIDTH),
        .RESET_VALUE    (ADDR_ZERO)
    )
    tap_number_storage
    (
        .clock          (clock),
        .clock_enable   (tap_number_load),
        .clear          (clear),
        .data_in        (tap_number),
        .data_out       (tap_number_current)
    );

// Then instantiate SRL dynamic shift registers.

// We use the Xilinx SRLs because implementing this as a [Register Pipeline](./Register_Pipeline.html) and a 
// [Multiplexer](./Multiplexer_Binary_Behavioural.html) consumes a very large amount of
// area for what it does.

    generate
    genvar i;

        for (i = 0; i < WORD_WIDTH; i=i+1) begin: per_bit

            if (PIPE_DEPTH == 32) begin

                SRLC32E
                #(
                    .INIT(32'h00000000) // Initial Value of Shift Register
                )
                data_pipeline
                (
                  .Q    (output_data [i]),      // SRL data output
                  .Q31  (),                     // SRL cascade output pin
                  .A    (tap_number_current),   // 5-bit shift depth select input
                  .CE   (shift_data),           // Clock enable input
                  .CLK  (clock),                // Clock input
                  .D    (input_data [i])        // SRL data input
                );

            end
            else if (PIPE_DEPTH == 16) begin

                SRL16E
                #(
                    .INIT(16'h0000) // Initial Value of Shift Register
                )
                data_pipeline
                (
                  .Q        (output_data        [i]),   // SRL data output
                  .A0       (tap_number_current [0]),   // Select[0] input
                  .A1       (tap_number_current [1]),   // Select[1] input
                  .A2       (tap_number_current [2]),   // Select[2] input
                  .A3       (tap_number_current [3]),   // Select[3] input
                  .CE       (shift_data),               // Clock enable input
                  .CLK      (clock),                    // Clock input
                  .D        (input_data         [i])    // SRL data input
                );

            end

        end

    endgenerate

endmodule

//# A Synchronous Register to Store and Control Data

// It may seem silly to implement a register module rather than let the HDL
// infer it, but doing so separates data and control at the most basic level,
// including various kinds of resets, which are part of control. This
// separation of data and control allows us to simplify the control logic and
// reduce the need for some routing resources.

//## Power-on-Reset
//
// On FPGAs, the initial state of registers is set in the configuration
// bitstream and applied by special power-on reset circuitry. The initial
// state of a design is available "for free" *and can be returned to at
// run-time*, which removes the need for that control and data logic.

//## Asynchronous Reset

// The asynchronous reset is not implemented here as its existence prevents
// register retiming, even if tied to zero. This limitation complicates design
// and reduces performance as we would have to manually place registers to
// properly pipeline logic. If you absolutely need an asynchronous reset for
// ASIC implementation or for some critical registers, use the
// [Register_areset](./Register_areset.html) instead.

//## Synchronous Reset (a.k.a. Clear)

// If you need to clear the register during normal operation, use the
// synchronous clear input. This may create extra logic, but that logic gets
// folded into other logic feeding data to the register, and would have been
// necessary anyway but present as another case in the surrounding logic.
// Having a clear input allows us to get to the initial power-on-reset state
// without complicating the design.

//## Implementation

// Let's begin with the usual front matter:

`default_nettype none

module Register
#(
    parameter WORD_WIDTH  = 0,
    parameter RESET_VALUE = 0
)
(
    input   wire                        clock,
    input   wire                        clock_enable,
    input   wire                        clear,
    input   wire    [WORD_WIDTH-1:0]    data_in,
    output  reg     [WORD_WIDTH-1:0]    data_out
);

    initial begin
        data_out = RESET_VALUE;
    end

// Here, we use the  "last assignment wins" idiom (See
// [Resets](./verilog.html#resets)) to implement reset.  This is also one
// place where we cannot use ternary operators, else the last assignment for
// clear (e.g.: `data_out <= (clear == 1'b1) ? RESET_VALUE : data_out;`) would
// override any previous assignment with the current value of `data_out` if
// `clear` is not asserted!

    always @(posedge clock) begin
        if (clock_enable == 1'b1) begin
            data_out <= data_in;
        end

        if (clear == 1'b1) begin
            data_out <= RESET_VALUE;
        end
    end

endmodule

//# Ceiling of log<sub>2</sub>(N) function

// Taken from the Verilog-2001 Language Reference Manual (LRM) standard example
// since $clog2() doesn't exist prior to Verilog-2005 (and thus,
// SystemVerilog).

// This returns the necessary number of bits to index N items with a binary
// integer. For example:

// * clog2(15) returns 4
// * clog2(16) returns 4
// * clog2(17) returns 5
// * etc...

// Bring in the function at the start of the body of your module like so:

//    `include "clog2_function.vh"

// Pass the function a value which, at elaboration time, is either a constant
// or an expression which evaluates to a constant. Then use that value as an
// integer for a localparam, genvar, etc...

// You don't need this function often, but it's very handy when a module
// receives some item count as a parameter, and you need to create an internal
// register to hold an index to those items (e.g.: a binary counter).

// We use a temp value for calculations since Vivado raises warnings if we
// internally assign a value to a function input port.

// Since this is an included file, it must be idempotent. (defined only once globally)

`ifndef CLOG2_FUNCTION
`define CLOG2_FUNCTION

function integer clog2;
    input integer value;
          integer temp;
    begin
        temp = value - 1;
        for (clog2 = 0; temp > 0; clog2 = clog2 + 1) begin
            temp = temp >> 1;
        end
    end
endfunction

`endif

//# A Reliable and Generic Binary Multiplexer (Behavioural Implementation)

// But first, some background on the problems with multiplexers...

//## Simulation and Synthesis Mismatch

// A pitfall in the Verilog language is the treatment of unknown X values in
// `if` statements, and it can cause a mismatch between the simulated and the
// synthesized behaviours. I have observed this exact mismatch in the field.
// This problem carries over into the design of multiplexers in general.
// Here's a contrived example, where we select one of two possibilities:

//     reg                         selector;
//     reg     [WORD_WIDTH-1:0]    option_A;
//     reg     [WORD_WIDTH-1:0]    option_B;
//     reg     [WORD_WIDTH-1:0]    result;
//     
//     always @(*) begin
//         if (selector == 1'b0) begin
//             result = option_A;
//         end
//         else begin
//             result = option_B;
//         end
//     end

// The problem here happens if `selector` is X or Z-valued. In real hardware,
// we would expect an X or Z `selector` to cause `result` to obtain an
// X value, *but the `if` statement treats X as false, and so falls through to
// the `else` case*. The simulation returns `option_B` while the synthesis
// returns `X`. This difference can also confuse verification efforts, because
// it can show a failure in simulation where there isn't one.

// Instead of `if` statements, we can use the ternary `?:` operator, which
// behaves as expected. Except in cases where both `option_A/option_B`
// evaluate to 1 or 0, an X or Z-valued `selector` will return an X value:

//     always @(*) begin
//         result = (selector == 1'b0) ? option_A : option_B;
//     end

//## Inflexible Implementations

// However, [the ternary operator gets impractical for more that two
// options](./verilog.html#ternary), and the `case` statement gets tedious and
// error-prone as the number of cases increases. And both are too rigid,
// requiring changes to the multiplexer implementation should the number of
// inputs change.

//## A Generic Solution

// Instead of implementing multiple multiplexers of specific sizes, we can
// replace them all with a single multiplexer module, implemented using
// a vector part select, which simulates and synthesizes correctly, and
// accepts a parameterized number of inputs.  In the following code, we can
// think of `selector` as "addressing" one of the `words_in` options.

// Rather than change the number of input ports at each design change, pass
// a concatenation of words to `words_in` with the zeroth element on the

// a concatenation of words to `words_in` with the zeroth element on the
// right. The `selector` then selects one of the input words. If the
// `selector` value is greater than the number of input words, the output is
// unknown (depends on synthesized logic). If the `selector` is X or Z, the
// output is X or Z.

// This multiplexer can also cleanly express little bits of arbitrary logic:
// set the inputs to the possible output values (constant or otherwise) of
// your function, and let the `selector` input get decoded to one of those
// values.

`default_nettype none

module Multiplexer_Binary_Behavioural
#(
    parameter       WORD_WIDTH          = 0,
    parameter       ADDR_WIDTH          = 0,
    parameter       INPUT_COUNT         = 0,

    // Do not set at instantiation
    parameter   TOTAL_WIDTH = WORD_WIDTH * INPUT_COUNT
)
(
    input   wire    [ADDR_WIDTH-1:0]    selector,
    input   wire    [TOTAL_WIDTH-1:0]   words_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

    initial begin
        word_out = {WORD_WIDTH{1'b0}};
    end

    always @(*) begin
        word_out = words_in[(selector * WORD_WIDTH) +: WORD_WIDTH];
    end

endmodule

//## Portability

// There's one problem here: if your HDL of choice does not have an analog of
// Verilog's vector part select, this design can't be translated. Thus, there
// exists [another, more structural implementation, which can be ported to
// other HDLs](./Multiplexer_Binary_Structural.html), and also expands the output
// function beyond the implicit Boolean OR found here.
